export type ContractRequirement = 'required' | 'optional' | 'not-used';

const REQUIRED: ContractRequirement = 'required';
const OPTIONAL: ContractRequirement = 'optional';
const UNUSED: ContractRequirement = 'not-used';

export type ActionContract = {
  element: ContractRequirement;
  elementCategory: ContractRequirement;
  value: ContractRequirement;
  expectedValue: ContractRequirement;
  key: ContractRequirement;
  headers: ContractRequirement;
  elementReplaceTextDataKey: ContractRequirement;
  isElementPathDynamic: ContractRequirement;
  isConcatenated: ContractRequirement;
};

const contract = (value: ActionContract): ActionContract => value;

